var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체와는 예전에도 몇 번 싸워 본 적이 있어요.","JPN":"侵食体とは以前にも何回か戦ったことがあります。","ENG":"I had fought C.O.s a few times before then.","TWN":"我之前也跟侵蝕體戰鬥過。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"돈을 벌려고 침식지대에서 희생자들의 유품을 수거하는 일을 몰래 해 봤거든요.","JPN":"お金を稼ぐため、侵食地帯で犠牲者の遺品を収集する仕事をこっそりしていたんですよ。","ENG":"I used to sneak out to Corrupted Areas to forage for valuables among the victims to make an extra buck.","TWN":"為了賺錢，曾經偷偷在侵蝕地區回收過犧牲者的遺物。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그렇게 많은 침식체들과 싸워 본 건 그 때가 처음이었어요.","JPN":"でもあんな大勢の侵食体と戦ったのは、あの時が初めてでした。","ENG":"But I never fought so many C.O.s until that day.","TWN":"但跟那麼多侵蝕體戰鬥，那次是第一次。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"속이 메스꺼워...... 벌써 지치면 안 되는데......","JPN":"気持ち悪くて吐きそう……でも疲れるにはまだ早い……","ENG":"I feel nauseous... But it's too early to give up now...","TWN":"噁呃……不能這麼快就倒下……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"팔이 아파...... 덩실이도 너무 무거워......","JPN":"腕が痛い……ふわりも重すぎる……","ENG":"My arms are sore... Dangler never felt so heavy...","TWN":"胳膊好疼……鐮刀也變得好沉重啊……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으앗?!","JPN":"わあっ！！","ENG":"Huh?!","TWN":"呃啊？！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"타이런트? 도망칠 길이 막혔어......?","JPN":"タイラント？　逃げ道がない……？","ENG":"A Tyrant? It cut off my escape route!","TWN":"那是侵蝕體暴君？逃走的路被堵住了……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"읏......","JPN":"うっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"무서워서 다리가 풀린다는 말이 무슨 뜻인지, 그 때 처음으로 알았어요.","JPN":"恐怖で足の力が抜けるという言葉の意味を、あの時初めて知りました。","ENG":"That's when I realized what it means to have your legs go weak from fear.","TWN":"那個時候是我第一次知道害怕到腿軟這句話的真正意思。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"혼자서 마주친 3종 침식체는...... 정말 크고...... 정말 무서웠거든요.","JPN":"一人で遭遇した第3種侵食体は……本当に大きくて……本当に怖かったんです。","ENG":"That Category 3 I faced all by myself... was too big... and too scary.","TWN":"一個人面對3類侵蝕體……真的很巨大……很可怕。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"덩실이를 짚고 있지 않았으면 아마 그 자리에서 주저앉았을 거예요.","JPN":"ふわりを握っていなかったら、たぶんその場で座り込んでしまったと思います。","ENG":"I would have collapsed on the spot if I didn't have Dangler to keep me propped up.","TWN":"如果不是拿著鐮刀，可能我會當場嚇得坐在地上。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"떨지 마...... 대시......! 떨면 안 돼......!","JPN":"怯えないで……ダッシュ……！　怯えちゃダメなの……！","ENG":"Don't tremble... Dash! Stop shaking!","TWN":"別抖……黛西……！別抖……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니도 최선을 다하고 있을 거야! 무서워하지 마......!","JPN":"リタお姉ちゃんだって今頃最善を尽くしている！　怖がることない……！","ENG":"Rita's probably doing her best right now too! Don't be scared!","TWN":"麗塔姐姐會盡力的！別害怕……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"시간만 끄는 거야! 불가능한 건 아니잖아!","JPN":"時間だけ稼げばいいから！　不可能なことでもない！","ENG":"All I need to do is buy some time! It's not impossible!","TWN":"只要好好拖延時間罷了！這不是不可能的事！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"3종 침식체라도...... 할 수 있어! 대시!","JPN":"第3種侵食体の相手でも……私ならできる、ダッシュ！","ENG":"Even if it's a Category 3... You can do this! Dash!","TWN":"即使是3類侵蝕體……你也可以的！黛西！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ngh!","TWN":"咳？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};